styles:
.blog-header {
      background: linear-gradient(135deg, #0d9488 0%, #14b8a6 100%);
      padding: 8rem 0 4rem;
      text-align: center;
      color: white;
    }
    .blog-header h1 {
      font-size: clamp(2rem, 5vw, 3rem);
      margin-bottom: 1.5rem;
      max-width: 900px;
      margin-left: auto;
      margin-right: auto;
    }
    .blog-meta {
      display: flex;
      justify-content: center;
      gap: 2rem;
      flex-wrap: wrap;
      font-size: 0.875rem;
      opacity: 0.9;
    }
    .blog-meta span {
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }
    .blog-content {
      background: white;
      padding: 4rem 0;
    }
    .blog-content .container {
      max-width: 800px;
    }
    .blog-image {
      width: 100%;
      border-radius: var(--radius-lg);
      margin-bottom: 2rem;
      box-shadow: var(--shadow-lg);
    }
    .blog-body {
      font-size: 1.125rem;
      line-height: 1.8;
      color: var(--text-secondary);
    }
    .blog-body h2 {
      font-size: 1.75rem;
      margin: 2.5rem 0 1rem;
      color: var(--text-primary);
    }
    .blog-body h3 {
      font-size: 1.375rem;
      margin: 2rem 0 1rem;
      color: var(--text-primary);
    }
    .blog-body p {
      margin-bottom: 1.5rem;
    }
    .blog-body ul, .blog-body ol {
      margin-bottom: 1.5rem;
      padding-left: 1.5rem;
    }
    .blog-body li {
      margin-bottom: 0.75rem;
    }
    .blog-body blockquote {
      border-left: 4px solid #0d9488;
      padding: 1.5rem;
      margin: 2rem 0;
      background: var(--bg-secondary);
      border-radius: 0 var(--radius-lg) var(--radius-lg) 0;
      font-style: italic;
    }
    .technique-card {
      background: var(--bg-secondary);
      border-radius: var(--radius-lg);
      padding: 2rem;
      margin-bottom: 1.5rem;
    }
    .technique-card h3 {
      color: #0d9488;
      margin-bottom: 1rem;
    }
    .technique-card p {
      margin-bottom: 0;
    }
    .bad-good {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1.5rem;
      margin: 2rem 0;
    }
    .bad-example, .good-example {
      padding: 1.5rem;
      border-radius: var(--radius-lg);
    }
    .bad-example {
      background: #fee2e2;
      border: 1px solid #fca5a5;
    }
    .good-example {
      background: #dcfce7;
      border: 1px solid #86efac;
    }
    .bad-example h4, .good-example h4 {
      margin-bottom: 1rem;
    }
    .bad-example h4 {
      color: #991b1b;
    }
    .good-example h4 {
      color: #166534;
    }
    .bad-example p, .good-example p {
      margin-bottom: 0;
      font-style: italic;
    }
    .blog-share {
      display: flex;
      gap: 1rem;
      margin-top: 3rem;
      padding-top: 2rem;
      border-top: 1px solid var(--border);
    }
    .blog-share span {
      font-weight: 600;
      color: var(--text-primary);
      align-self: center;
    }
    .share-btn {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 40px;
      height: 40px;
      border-radius: 50%;
      background: var(--bg-secondary);
      color: var(--text-secondary);
      transition: var(--transition);
    }
    .share-btn:hover {
      background: #0d9488;
      color: white;
    }
    .back-link {
      display: inline-flex;
      align-items: center;
      gap: 0.5rem;
      color: white;
      font-weight: 500;
      margin-bottom: 2rem;
      opacity: 0.9;
    }
    .back-link:hover {
      text-decoration: underline;
      opacity: 1;
    }
    @media (max-width: 768px) {
      .bad-good {
        grid-template-columns: 1fr;
      }
      .blog-header {
        padding: 6rem 0 3rem;
      }
      .blog-content {
        padding: 3rem 0;
      }
    }
